const pages = $json.pages;
let boundaries = [1];

for (let i = 1; i < pages.length; i++) {
  const prev = pages[i-1].text;
  const current = pages[i].text;

  const pageReset = /\bpage\s*1\b/i.test(current);
  const dateShift = /\b\d{1,2}\/\d{1,2}\/\d{2,4}\b/.test(current) && !prev.includes(current.match(/\b\d{1,2}\/\d{1,2}\/\d{2,4}\b/));

  if (pageReset || dateShift) {
    boundaries.push(i+1);
  }
}

return [{ boundaries, pages }];

